bool get_bit(char *ptr, size_t offset)
{
    return (((*(ptr + offset / 8)) >> (offset % 8)) & 1);
}

void set_bit(char *ptr, size_t offset, bool value)
{
    char temp = (*(ptr + offset / 8)) & (~(1 << offset % 8));

    temp |= (value << offset % 8);
    (*(ptr + offset / 8)) = temp;
}

void print_sieve(char *buffer, size_t size)
{
    for (size_t i = 0; i < size; i += 1) {
        if (get_bit(buffer, i) == 0)
            printf("%lu\n", i + 2);
    }
}

void erathostene(size_t limit)
{
    size_t buf_size = (limit < 8 ? 1 : limit / 8);
    char *buffer = alloca(limit);

    memset(buffer, 0, buf_size);
    for (size_t i = 2; i < limit; i += 1) {
        size_t idx = i - 2;
        if (get_bit(buffer, i) == 0) {
            for (size_t j = idx + i; j < limit; j += i) {
                if ((j + 2) % i == 0) {
                    set_bit(buffer, j, 1);
                }
            }
        }
    }
    print_sieve(buffer, limit);
}

int* sieve_of_eratosthenes(int n, int* out_size)
{
    if (n < 2) {
        *out_size = 0;
        return NULL;
    }

    char *is_composite = (char *)calloc((size_t)n + 1, sizeof(char));
    int *result = (int *)malloc(((size_t)n + 1) * sizeof(int));
    if (!is_composite || !result) {
        free(is_composite);
        free(result);
        *out_size = 0;
        return NULL;
    }

    int count = 0;
    for (int i = 2; i <= n; i++) {
        if (!is_composite[i]) {
            result[count++] = i;
            if ((long long)i * i <= n) {
                for (int j = i * i; j <= n; j += i) {
                    is_composite[j] = 1;
                }
            }
        }
    }

    free(is_composite);
    *out_size = count;
    return result;
}

